import pytest
from smalllib import add


def test_add_integers():
    assert add(1, 2) == 3


def test_add_floats():
    assert add(0.5, 0.25) == 0.75


def test_add_strings():
    assert add("a", "b") == "ab"


def test_add_lists():
    assert add([1], [2]) == [1, 2]


def test_add_incompatible_types_raises():
    with pytest.raises(TypeError):
        add(1, "a")
